// Ambil semua data dari Google Sheets
const items = $input.all();

console.log('Total items:', items.length);

// Validasi data
if (!items || items.length === 0) {
  throw new Error('Tidak ada data yang dibaca dari Google Sheets!');
}

// Log sample data untuk debugging
console.log('Sample first item:', JSON.stringify(items[0].json));

// Object untuk menyimpan data per jam
const hourlyData = {};

// Counter untuk tracking
let processedCount = 0;
let skippedCount = 0;

// Proses setiap row data
items.forEach((item, index) => {
  try {
    // Get data dengan berbagai kemungkinan nama kolom
    const rawData = item.json;

    // Coba berbagai nama kolom yang mungkin
    const hour = rawData['Jam Posting'] || rawData['jam posting'] || rawData['Jam'] || rawData['jam'];
    const likes = parseInt(rawData['Likes'] || rawData['likes'] || 0);
    const comments = parseInt(rawData['Comments'] || rawData['comments'] || 0);
    const shares = parseInt(rawData['Shares'] || rawData['shares'] || 0);
    const platform = rawData['Platform'] || rawData['platform'] || 'Unknown';

    // Skip jika jam tidak valid atau undefined
    if (hour === undefined || hour === null || hour === '') {
      console.log(`Skipping row ${index + 1}: hour is undefined`);
      skippedCount++;
      return;
    }

    // Convert hour ke number jika string
    const hourNum = typeof hour === 'number' ? hour : parseInt(hour);

    // Validasi hour range (0-23)
    if (isNaN(hourNum) || hourNum < 0 || hourNum > 23) {
      console.log(`Skipping row ${index + 1}: invalid hour ${hour}`);
      skippedCount++;
      return;
    }

    // Hitung total engagement (bobot: likes x1, comments x2, shares x3)
    const engagement = likes + (comments * 2) + (shares * 3);

    // Initialize data untuk jam ini jika belum ada
    if (!hourlyData[hourNum]) {
      hourlyData[hourNum] = {
        hour: hourNum,
        totalEngagement: 0,
        count: 0,
        totalLikes: 0,
        totalComments: 0,
        totalShares: 0,
        platforms: {}
      };
    }

    // Akumulasi data
    hourlyData[hourNum].totalEngagement += engagement;
    hourlyData[hourNum].count += 1;
    hourlyData[hourNum].totalLikes += likes;
    hourlyData[hourNum].totalComments += comments;
    hourlyData[hourNum].totalShares += shares;

    // Track platform distribution
    if (!hourlyData[hourNum].platforms[platform]) {
      hourlyData[hourNum].platforms[platform] = 0;
    }
    hourlyData[hourNum].platforms[platform] += 1;

    processedCount++;

  } catch (error) {
    console.error(`Error processing row ${index + 1}:`, error.message);
    skippedCount++;
  }
});

console.log(`Processed: ${processedCount}, Skipped: ${skippedCount}`);

// Validasi hasil
if (Object.keys(hourlyData).length === 0) {
  throw new Error(`Tidak ada data valid yang bisa diproses! Processed: ${processedCount}, Skipped: ${skippedCount}`);
}

// Hitung rata-rata dan buat array
const results = Object.values(hourlyData).map(data => {
  const mostUsedPlatform = Object.keys(data.platforms).reduce((a, b) => 
    data.platforms[a] > data.platforms[b] ? a : b
  );

  return {
    jam: `${String(data.hour).padStart(2, '0')}:00`,
    avgEngagement: Math.round(data.totalEngagement / data.count),
    jumlahPost: data.count,
    avgLikes: Math.round(data.totalLikes / data.count),
    avgComments: Math.round(data.totalComments / data.count),
    avgShares: Math.round(data.totalShares / data.count),
    platformTerbanyak: mostUsedPlatform,
    engagementScore: Math.round((data.totalEngagement / data.count) * 100) / 100
  };
});

// Sort berdasarkan engagement tertinggi
results.sort((a, b) => b.avgEngagement - a.avgEngagement);

// Ambil top 10 jam terbaik
const top10 = results.slice(0, 10);

// Tambahkan ranking
const rankedResults = top10.map((item, index) => ({
  ranking: index + 1,
  ...item,
  rekomendasi: index < 3 ? '⭐ SANGAT DIREKOMENDASIKAN' : index < 5 ? '✅ DIREKOMENDASIKAN' : '👍 CUKUP BAIK'
}));

// Tambahkan timestamp analisis
const analysisDate = new Date().toLocaleString('id-ID', {
  timeZone: 'Asia/Jakarta',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit'
});

const finalResults = rankedResults.map(item => ({
  ...item,
  tanggalAnalisis: analysisDate,
  totalDataDianalisis: processedCount
}));

console.log('Final results count:', finalResults.length);

return finalResults.map(item => ({ json: item }));

// Ambil hasil analisis dari input sebelumnya
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { message: '❌ Tidak ada data untuk dikirim' } }];
}

// Ambil top 5 jam terbaik
const top5 = items.slice(0, 5);
const totalData = items[0].json.totalDataDianalisis || 'N/A';
const tanggalAnalisis = items[0].json.tanggalAnalisis || new Date().toLocaleString('id-ID');

// Format pesan Telegram dengan emoji dan formatting
let message = `📊 *HASIL ANALISIS WAKTU POSTING TERBAIK*\n`;
message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
message += `🏆 *TOP 5 JAM TERBAIK:*\n\n`;

top5.forEach((item, index) => {
  const data = item.json;
  const medal = index === 0 ? '🥇' : index === 1 ? '🥈' : index === 2 ? '🥉' : `${index + 1}.`;

  message += `${medal} *JAM ${data.jam}*\n`;
  message += `   📈 Avg Engagement: *${data.avgEngagement}*\n`;
  message += `   ❤️ Avg Likes: ${data.avgLikes}\n`;
  message += `   💬 Avg Comments: ${data.avgComments}\n`;
  message += `   🔄 Avg Shares: ${data.avgShares}\n`;
  message += `   📱 Platform: ${data.platformTerbanyak}\n`;
  message += `   📊 Total Post: ${data.jumlahPost} post\n`;
  message += `   ${data.rekomendasi}\n\n`;
});

message += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
message += `💡 *REKOMENDASI:*\n`;
message += `Posting pada jam *${top5[0].json.jam}* memberikan engagement tertinggi dengan rata-rata *${top5[0].json.avgEngagement}* engagement!\n\n`;

message += `📅 Analisis: ${tanggalAnalisis}\n`;
message += `📝 Total data: ${totalData} post\n\n`;

message += `_Gunakan insight ini untuk optimasi strategi posting Anda!_ 🚀`;

return [{ json: { 
  chatId: '',  // Akan diisi dari credential atau parameter
  message: message,
  parseMode: 'Markdown'
} }];
